#!/usr/bin/env python3"""Diagnostic script to test jira_scenario issues"""import asyncioimport sysimport os# Add parent directory to path for importscurrent_dir = os.path.dirname(os.path.abspath(__file__))parent_dir = os.path.dirname(current_dir)sys.path.append(parent_dir)from src.agentic_ai.utils import load_system_message, create_anthropic_client, AnthropicModels, get_required_envfrom autogen_agentchat.agents import AssistantAgentfrom autogen_agentchat.teams import RoundRobinGroupChatfrom autogen_agentchat.conditions import TextMentionTerminationfrom autogen_ext.tools.mcp import StdioServerParams, McpWorkbenchfrom dotenv import load_dotenvload_dotenv()async def diagnose_agents():    print("🔍 Diagnosing jira_scenario issues...")    # Test 1: File loading    print("\n1️⃣ Testing file loading...")    script_dir = current_dir    files_to_check = [        "assets/prompts/bug_analyst_prompt.txt",        "assets/prompts/playwright_analyst_prompt.txt",        "assets/prompts/jira_agentic_ai_task.txt"    ]    for file_path in files_to_check:        full_path = os.path.join(script_dir, file_path)        exists = os.path.exists(full_path)        print(f"   📄 {file_path}: {'✅' if exists else '❌'} {full_path}")        if exists:            try:                content = load_system_message(full_path)                print(f"      Content length: {len(content)} chars")                print(f"      First 100 chars: {content[:100]}...")            except Exception as e:                print(f"      ❌ Error loading: {e}")    # Test 2: Agent creation    print("\n2️⃣ Testing agent creation...")    try:        anthropic_client = create_anthropic_client(AnthropicModels.SONNET)        print("   ✅ Anthropic client created")        # Test workbench creation        jira_server_params = StdioServerParams(            command="uvx",            args=["mcp-atlassian"],            env={                "JIRA_URL": get_required_env("JIRA_URL"),                "JIRA_USERNAME": get_required_env("JIRA_USERNAME"),                "JIRA_API_TOKEN": get_required_env("JIRA_API_TOKEN"),                "TOOLSETS": "all",            },            read_timeout_seconds=60,        )        jira_workbench = McpWorkbench(jira_server_params)        print("   ✅ Jira workbench created")        playwright_server_params = StdioServerParams(            command="npx", args=["@playwright/mcp@latest"], env={}, read_timeout_seconds=60        )        playwright_workbench = McpWorkbench(playwright_server_params)        print("   ✅ Playwright workbench created")    except Exception as e:        print(f"   ❌ Error creating components: {e}")        return    # Test 3: Simple agent interaction    print("\n3️⃣ Testing simple agent interaction...")    try:        async with jira_workbench as jira:            # Create just the bug analyst            bug_analyst = AssistantAgent(                name="bugAnalyst",                model_client=anthropic_client,                workbench=jira,                system_message="""You are a Bug Analyst. When asked to create a test, respond with:'I will create a basic smoke test for GreenKart application:1. Navigate to https://rahulshettyacademy.com/seleniumPractise/#/2. Add items to cart3. Proceed to checkoutHANDOFF TO AUTOMATION'"""            )            # Simple test with direct response            print("   📨 Testing direct agent response...")            # Create a minimal team            team = RoundRobinGroupChat(                participants=[bug_analyst],                termination_condition=TextMentionTermination("HANDOFF TO AUTOMATION"),                max_turns=2,            )            task = "Create a simple smoke test for GreenKart"            print("   🚀 Starting agent conversation...")            conversation_count = 0            async for message in team.run_stream(task=task):                conversation_count += 1                print(f"\n   📝 Message {conversation_count}:")                print(f"      Source: {getattr(message, 'source', 'Unknown')}")                print(f"      Type: {type(message).__name__}")                if hasattr(message, 'content'):                    print(f"      Content: {message.content[:200]}...")                else:                    print(f"      Data: {str(message)[:200]}...")            print(f"\n   ✅ Conversation completed with {conversation_count} messages")    except Exception as e:        print(f"   ❌ Error in agent interaction: {e}")        import traceback        traceback.print_exc()    finally:        await anthropic_client.close()if __name__ == "__main__":    asyncio.run(diagnose_agents())